import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F07_存貨週轉效率同業對比_投資研究員.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F07_存貨週轉效率同業對比_投資研究員.md"}'),i={name:"審計報告庫/財務審計/3135_凌航/20260430/F07_存貨週轉效率同業對比_投資研究員.md"};function l(n,a,s,_,h,c){return e(),r("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f07-存貨週轉效率同業對比-投資研究員-審計報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 投資研究員 審計報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-投資研究員-審計報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：凌航 2025Q4 存貨週轉天數為 82.5 天，顯著優於同業中位值（~130天），具備模組業頂尖的去化效率。整體營運週期雖擴張，但仍穩居產業「效率領先者」。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至 2025 年 Q4 最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：DIO 82.5 天（同業最優）、DSO 44.9 天（優化中）、營運週期 127.4 天（擴張 17%）。</li><li><strong>診斷見解</strong>：評級 S (優)。凌航 DIO 較宇瞻 (148.3) 與十銓 (124.2) 展現出極強的通路週轉力。雖然 DIO 較 2023 年（55 天）上升 50%，但遠低於產業平均 146 天，且 DSO 有效抵銷部分庫存壓力，資產變現能力極佳。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="子議題一-週轉競爭優勢對位" tabindex="-1">[子議題一：週轉競爭優勢對位] <a class="header-anchor" href="#子議題一-週轉競爭優勢對位" aria-label="Permalink to &quot;[子議題一：週轉競爭優勢對位]&quot;">​</a></h3><ul><li><strong>核心重點</strong>：凌航 DIO 為 82.5 天，顯著優於宜鼎（115.8天）、十銓（124.2天）及宇瞻（148.3天）。</li><li><strong>深度見解</strong>：凌航週轉天數領先同業 30-65 天，顯示其在 DRAM/NAND 市場擁有更精準的訂單預測與通路去化動能。其極致的 DIO 反映了「小而美」的經營靈活性，能在價格波動劇烈的記憶體市場中，比同業更快完成庫存清洗，降低跌價風險。</li></ul><h3 id="子議題二-營運週期擴張分析" tabindex="-1">[子議題二：營運週期擴張分析] <a class="header-anchor" href="#子議題二-營運週期擴張分析" aria-label="Permalink to &quot;[子議題二：營運週期擴張分析]&quot;">​</a></h3><ul><li><strong>核心重點</strong>：營運週期由 2023 年 108.6 天擴張至 127.4 天；DSO 由 53.5 天優化至 44.9 天。</li><li><strong>深度見解</strong>：整體週期雖擴張 18.8 天，但主因是 DIO 的策略性拉升。值得注意的是，DSO 的改善顯示公司在擴張期仍保有強大的客戶收款議價權。2025 年底存貨激增至 26.2 億，結合 12 月營收月增趨勢，判定此為針對 DDR5/AI 需求的上行備貨，而非呆滯積壓，營運流速仍處健康區間。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：庫存跌價與市場反轉風險</strong>。凌航 2025 年底存貨水位較 2024 年底暴增 266%，資產佔比急升。若 2026 年 AI 伺服器需求不如預期或記憶體價格閃崩，龐大的高價庫存將面臨嚴重的資產減損壓力，112 年曾提列 1.2 億損失之紀錄可能因高基期而倍增。</li><li><strong>空頭風險二：利息支出侵蝕與現金流壓力</strong>。雖然營運效率高，但庫存擴張伴隨短期借款由 5.2 億飆升至 7.5 億以上。在升息環境下，高額持倉成本將侵蝕毛利淨額。若 2026 Q1 營收增速無法覆蓋利息支出，現金流恐出現惡化，進而壓縮股利配發空間。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: 2024-2025 財務數據 (庫存餘額 2,618,809K, 12月營收 1,176,074K)。</li><li><strong>StatementDog</strong>: 3135 Q4 DIO (82.5), DSO (44.9), Op Cycle (127.4)。</li><li><strong>年報/法說</strong>: 2023 年報 P.79 (DIO 55.05, DSO 53.51), P.83 (策略備貨說明)。</li><li><strong>關鍵核對碼</strong>: <code>DIO_3135_82.5 vs Industry_146.02; Inventory_YoY_266%</code></li></ul>',17)])])}const g=t(i,[["render",l]]);export{u as __pageData,g as default};
